+triggers.register("packageReleases", async (ctx, change) => {
+  if (change.operation === "insert") return;
+  if (change.operation === "update" && change.oldDoc.softDeletedAt === change.newDoc.softDeletedAt) {
+    return;
+  }
+  const packageId =
