+  runtimeId?: string;
+  summary?: string;
+  latestVersion?: string | null;
+  compatibility?: Doc<"packages">["compatibility"];
+  capabilities?: Doc<"packages">["capabilities"];
+  verification?: Doc<"packages">["verification"];
+  createdAt: number;
+  updatedAt: number;
+};

