+          };
+        }
+      }
+
+      done = page.isDone;
+      cursor = page.continueCursor;
+      offset = 0;
+      pageSize = effectivePageSize;
+    }
+
+    return {
+      page: collected,
+      isDone: done,
+      continueCursor: encodeSkillCatalogCursor({ cursor, offset, pageSize, done }),
+    };
